UPDATE product_join_progress
SET progress_status = 'EXPIRED', updated_dt = SYSDATE
WHERE user_no = #{userNo}
  AND product_no = #{productNo}
  AND progress_status = 'IN_PROGRESS'
  AND join_progress_no != #{keepNo}

UPDATE product_join_progress
SET progress_status = 'EXPIRED', updated_dt = SYSDATE
WHERE user_no = #{userNo}
  AND product_no = #{productNo}
  AND progress_status = 'IN_PROGRESS'

UPDATE product_join_progress
SET progress_status = 'COMPLETED', updated_dt = SYSDATE
WHERE user_no = #{userNo}
  AND product_no = #{productNo}
  AND progress_status = 'IN_PROGRESS'

